import { ethers } from 'ethers';

const provider = new ethers.providers.InfuraProvider(process.env.INFURA_PROJECT_ID, process.env.INFURA_PROJECT_SECRET);
const signer = provider.getSigner();

async function sendTransaction() {
  const transaction = {
    to: '0x...', // Replace with the contract address
    value: ethers.utils.parseEther('1'), // Replace with the amount of ETH to send
  };

  try {
    await signer.sendTransaction(transaction);
    console.log('Transaction sent successfully');
  } catch (error) {
    console.error('Error sending transaction:', error);
  }
}